import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

// A deterministic daily time series (no randomness, so the demo is stable).
// Enough points that a pinch/pan actually has somewhere to go.
function momentumSeries() {
  var out = []
  var start = new Date('2023-01-01').getTime()
  var day = 86400000
  var v = 120
  for (var i = 0; i < 220; i++) {
    // smooth composite drift: a couple of sines plus a slow trend
    v = 120 + 38 * Math.sin(i / 13) + 18 * Math.sin(i / 4.5) + i * 0.32
    out.push([start + i * day, Math.round(v * 100) / 100])
  }
  return out
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [{ name: 'Reading', data: momentumSeries() }],
    options: {
      chart: {
        id: 'momentumChart',
        height: 400,
        type: 'area',
        fontFamily: 'Helvetica, Arial, sans-serif',
        animations: { enabled: false },
        toolbar: {
          autoSelected: 'pan',
          tools: {
            pan: true,
            zoom: true,
            zoomin: true,
            zoomout: true,
            reset: true,
            download: false,
          },
        },
        zoom: {
          enabled: true,
          type: 'x',
          pinch: true,
        },
        pan: {
          inertia: true,
          friction: 0.92,
        },
      },
      colors: ['#4f46e5'],
      dataLabels: { enabled: false },
      stroke: { curve: 'smooth', width: 2 },
      fill: {
        type: 'gradient',
        gradient: {
          shadeIntensity: 0.3,
          opacityFrom: 0.35,
          opacityTo: 0.03,
          stops: [0, 100],
        },
      },
      title: { text: 'Sensor reading (220 days)', align: 'left' },
      subtitle: {
        text: 'Pinch to zoom, two-finger pan, flick to glide',
        align: 'left',
      },
      xaxis: {
        type: 'datetime',
      },
      yaxis: {
        labels: {
          formatter: function (v) {
            return Math.round(v)
          },
        },
      },
      tooltip: { x: { format: 'dd MMM yyyy' } },
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, so reach the live instance by
    // its chart.id. Poll until it exists, then wire the same readout the vanilla
    // build does. (momentumSeries lives in the shared head script.)
    let chart
    const timer = window.setInterval(() => {
      chart = ApexCharts.getChartByID('momentumChart')
      if (!chart) return
      window.clearInterval(timer)

      const gestureEl = document.getElementById('gesture')
      const windowEl = document.getElementById('window')

      const fmt = (ts) => new Date(ts).toISOString().slice(0, 10)
      const showWindow = (label, xaxis) => {
        gestureEl.innerHTML = label
        if (xaxis && xaxis.min != null && xaxis.max != null) {
          windowEl.innerHTML = fmt(xaxis.min) + '  to  ' + fmt(xaxis.max)
        }
      }

      // zoomed fires at the end of a pinch (and on wheel / toolbar zoom); scrolled
      // fires continuously while panning and once the inertia glide comes to rest.
      chart.addEventListener('zoomed', (c, opts) =>
        showWindow('zoomed', opts.xaxis),
      )
      chart.addEventListener('scrolled', (c, opts) =>
        showWindow('panned', opts.xaxis),
      )
    }, 50)

    return () => {
      window.clearInterval(timer)
    }
  }, [])

  return (
    <div>
      <div className="panel">
        <div className="readout">
          <span className="pill" id="gesture">
            ready
          </span>
          <span>
            window: <b id="window">full range</b>
          </span>
        </div>

        <div className="gestures">
          <div className="gesture">
            <h4>Pinch</h4>
            <p>
              Two fingers, spread or squeeze. Zooms the x-axis around the point
              between your fingers, frame by frame.
            </p>
          </div>
          <div className="gesture">
            <h4>Two-finger drag</h4>
            <p>
              Slide both fingers together to pan while pinched. The point under
              your fingers stays put.
            </p>
          </div>
          <div className="gesture">
            <h4>Flick to glide</h4>
            <p>
              In pan mode, drag with one finger and release with speed. The
              chart keeps gliding and eases to a stop at the data edge.
            </p>
          </div>
        </div>
      </div>

      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="area"
          height={400}
        />
      </div>

      <div className="panel">
        <div className="note">
          Momentum is on by default: <code>chart.zoom.pinch</code> and
          <code>chart.pan.inertia</code>. Pinch-zoom and kinetic inertia are
          <b>touch gestures</b>, so try this on a phone or tablet, or turn on
          device (touch) emulation in your browser dev tools. On desktop you can
          still mouse-wheel zoom and use the toolbar's pan tool; the readout
          above tracks the x-window from the <code>zoomed</code> and{' '}
          <code>scrolled</code> events. A one-finger drag that is mostly
          vertical is treated as a page scroll (axis rails), so the chart never
          traps the page.
        </div>
      </div>
    </div>
  )
}

export default ApexChart

